from agent import *from models.products import *import timeimport randomimport rePRODS_NAME = []def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context: dict[str, str], session: Session):    session.browser.use_new_parser = True    session.queue(Request('https://www.mipow.com/collections/all'), process_revlist, dict())def process_revlist(data: Response, context: dict[str, str], session: Session):    strip_namespace(data)    time.sleep(random.uniform(1, 3))    prods = data.xpath('//div[contains(@class, "product__title")]/a')    for prod in prods:        name = prod.xpath('text()').string()        url = prod.xpath('@href').string()        if name:            name = re.split(r'/ ?\w+$', name, maxsplit=1)[0]            if name not in PRODS_NAME:                PRODS_NAME.append(name)                session.queue(Request(url), process_review, dict(name=name, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_revlist, dict())def process_review(data: Response, context: dict[str, str], session: Session):    strip_namespace(data)    time.sleep(random.uniform(1, 3))    product = Product()    product.name = context['name']    product.url = context['url']    product.ssid = product.url.split('/')[-1]    product.category = 'Gadgets'    review = Review()    review.type = 'pro'    review.title = data.xpath('//h1[contains(@class, "title")]/text()').string()    review.url = product.url    review.ssid = product.ssid    excerpt = data.xpath('//div[@itemprop="description"]/p//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//div[@itemprop="description"]/div[@style="text-align: center;"]//text()').string(multiple=True)    if excerpt:        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)